/*
  Design system and global styles for the home renovation & extension builder site.
  The styling closely matches the provided pastel cream + deep blue marketing design.
*/

:root {
  /* Brand colors */
  --color-primary: #244A7C;       /* Deep desaturated navy used for typography */
  --color-primary-cream: #FDF1CF; /* Pastel cream background */

  --color-secondary-blue: #C8E2FF; /* Soft blue pill background */
  --color-secondary-white: #FFFFFF;

  --color-accent: #244A7C;

  --color-neutral-100: #FFFFFF;
  --color-neutral-200: #F5F5F5;
  --color-neutral-300: #CCCCCC;

  --color-success: #2E8B57;
  --color-error: #C0392B;
  --color-warning: #E67E22;
  --color-info: #2F80ED;

  --color-text-main: #244A7C;
  --color-text-muted: rgba(36, 74, 124, 0.7);

  /* Typography */
  --font-heading: "DM Sans", -apple-system, BlinkMacSystemFont, "Helvetica Neue", Arial, sans-serif;
  --font-body: "Source Sans 3", -apple-system, BlinkMacSystemFont, "Helvetica Neue", Arial, sans-serif;

  --font-size-h1: 3rem;   /* 48px */
  --font-size-h2: 2.25rem;/* 36px */
  --font-size-h3: 1.5rem; /* 24px */
  --font-size-body: 1rem; /* 16px */
  --font-size-small: 0.875rem; /* 14px */

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing scale (4px base) */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Radii */
  --radius-small: 4px;
  --radius-medium: 8px;
  --radius-pill: 999px;

  /* Layout */
  --page-max-width: 1120px;
}

/* Global reset & base styles */

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body.site {
  min-height: 100vh;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-text-main);
  background-color: var(--color-primary-cream);
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: underline;
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

.site-header,
.site-footer {
  width: 100%;
}

.site-content {
  min-height: 40vh;
  padding: var(--space-6) var(--space-3) var(--space-7);
}

@media (min-width: 1024px) {
  .site-content {
    padding-inline: 40px;
  }
}

/* Header */

.site-header {
  background-color: var(--color-primary-cream);
}

.header-inner {
  max-width: var(--page-max-width);
  margin: 0 auto;
  padding: var(--space-4) var(--space-3);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-3);
}

@media (min-width: 1024px) {
  .header-inner {
    padding-inline: 0;
  }
}

.brand {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  font-family: var(--font-heading);
  font-weight: 700;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--color-neutral-100);
}

.brand-mark {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background-color: var(--color-primary);
  font-size: 0.9rem;
}

.brand-text {
  font-size: 1.1rem;
  color: var(--color-primary);
}

.brand--footer .brand-text {
  color: var(--color-primary);
}

.site-nav {
  flex: 1 1 auto;
}

.nav-list {
  display: flex;
  flex-wrap: wrap;
  justify-content: flex-end;
  align-items: center;
  gap: var(--space-3);
  list-style: none;
  margin: 0;
  padding: 0;
}

.nav-item {
  flex: 0 0 auto;
}

.nav-link {
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font-body);
  font-weight: 500;
  font-size: 0.95rem;
  color: var(--color-text-main);
  padding: 8px 0;
  border-radius: var(--radius-pill);
  transition: color 0.15s ease, background-color 0.15s ease;
}

.nav-link:hover,
.nav-link:focus-visible {
  text-decoration: none;
  color: var(--color-accent);
}

.nav-link--cta {
  padding-inline: 22px;
  background-color: var(--color-secondary-blue);
  color: var(--color-primary);
}

.nav-link--cta:hover,
.nav-link--cta:focus-visible {
  background-color: #b4d5ff;
}

/* Footer */

.site-footer {
  background-color: var(--color-primary-cream);
  border-top: 1px solid rgba(36, 74, 124, 0.08);
}

.footer-inner {
  max-width: var(--page-max-width);
  margin: 0 auto;
  padding: var(--space-5) var(--space-3) var(--space-4);
  display: flex;
  flex-direction: column;
  gap: var(--space-4);
}

@media (min-width: 768px) {
  .footer-inner {
    flex-direction: row;
    align-items: center;
    justify-content: space-between;
  }
}

.footer-branding {
  flex: 0 0 auto;
}

.footer-nav {
  flex: 1 1 auto;
}

.footer-links {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-3);
  justify-content: center;
}

@media (min-width: 768px) {
  .footer-links {
    justify-content: flex-end;
  }
}

.footer-link {
  font-size: var(--font-size-small);
  color: var(--color-text-muted);
  transition: color 0.15s ease;
}

.footer-link:hover,
.footer-link:focus-visible {
  color: var(--color-text-main);
  text-decoration: none;
}

.footer-meta {
  flex-basis: 100%;
  text-align: center;
}

@media (min-width: 768px) {
  .footer-meta {
    text-align: left;
    order: -1;
  }
}

.footer-copy {
  margin: 0;
  font-size: var(--font-size-small);
  color: var(--color-text-muted);
}

/* Headings (for page content, maintaining design language) */

h1,
h2,
h3 {
  font-family: var(--font-heading);
  font-weight: 600;
  color: var(--color-text-main);
  margin: 0 0 var(--space-3);
}

h1 {
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
}

h2 {
  font-size: var(--font-size-h2);
}

h3 {
  font-size: var(--font-size-h3);
}

p {
  margin: 0 0 var(--space-3);
  color: var(--color-text-muted);
}

.small-text {
  font-size: var(--font-size-small);
}

/* Utility classes */

.container {
  max-width: var(--page-max-width);
  margin: 0 auto;
  padding-inline: var(--space-3);
}

.text-center {
  text-align: center;
}

.text-right {
  text-align: right;
}

.mt-0 { margin-top: 0; }
.mt-3 { margin-top: var(--space-3); }
.mt-4 { margin-top: var(--space-4); }

.mb-0 { margin-bottom: 0; }
.mb-3 { margin-bottom: var(--space-3); }
.mb-4 { margin-bottom: var(--space-4); }

/* Buttons (for reuse on interior pages, following pill style) */

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 10px 24px;
  border-radius: var(--radius-pill);
  font-family: var(--font-body);
  font-weight: 500;
  font-size: 0.95rem;
  border: 1px solid transparent;
  background-color: transparent;
  color: var(--color-text-main);
  cursor: pointer;
  text-decoration: none;
  transition: background-color 0.15s ease, color 0.15s ease, border-color 0.15s ease;
}

.btn-outline-primary {
  border-color: var(--color-primary);
}

.btn-outline-primary:hover,
.btn-outline-primary:focus-visible {
  background-color: rgba(36, 74, 124, 0.04);
}

.btn-filled-soft {
  background-color: var(--color-secondary-blue);
  color: var(--color-primary);
}

.btn-filled-soft:hover,
.btn-filled-soft:focus-visible {
  background-color: #b4d5ff;
}
